13		"github.com/DocumentDrivenDX/ddx/internal/config"
14	)
15	
16	// ExecutionsMirrorIndexFile is the local pointer file that lists every
17	// successfully mirrored bundle. One JSON object per line.
18	const ExecutionsMirrorIndexFile = ".ddx/executions/mirror-index.jsonl"
19	
20	// ExecutionsMirrorLogFile records mirror upload attempts and failures so
21	// operators can diagnose mirror-side issues without re-running execute-bead.
22	const ExecutionsMirrorLogFile = ".ddx/agent-logs/mirror.log"
23	
24	// MirrorIndexEntry is one row of the local mirror-index.jsonl pointer file.
25	type MirrorIndexEntry struct {
26		AttemptID  string    `json:"attempt_id"`
27		BeadID     string    `json:"bead_id,omitempty"`
28		MirrorURI  string    `json:"mirror_uri"`
29		UploadedAt time.Time `json:"uploaded_at"`
30		ByteSize   int64     `json:"byte_size"`
31		Kind       string    `json:"kind"`
32	}
33	
34	// MirrorBackend uploads and retrieves bundle directories.
35	type MirrorBackend interface {
36		// Kind returns the backend identifier (matches the configured kind, e.g. "local").
37		Kind() string
38		// Upload copies the resolved set of files in srcDir to a destination derived
39		// from the rendered destination URI/path. Returns the canonical mirror URI
40		// for the bundle along with the total bytes uploaded.
41		Upload(destURI, srcDir string, includeFilter func(relPath string) bool) (string, int64, error)
42		// Fetch downloads a previously mirrored bundle to destDir.
43		Fetch(mirrorURI, destDir string) error
44	}
45	
46	// MirrorRequest carries everything needed to mirror one execute-bead bundle.
47	type MirrorRequest struct {
48		ProjectRoot string
49		AttemptID   string
50		BeadID      string
51		BundleDir   string // absolute path to .ddx/executions/<attempt-id>/
52		Cfg         *config.ExecutionsMirrorConfig
53	}
54	
55	// allMirrorParts is the canonical default include list — every part of the
56	// bundle. Used when ExecutionsMirrorConfig.Include is empty.
57	var allMirrorParts = []string{"manifest", "prompt", "result", "usage", "checks", "embedded"}
58	
59	// fileForPart returns the relative bundle path (or directory prefix) for a
60	// part name. The "embedded" part is a directory; the rest are single files.
61	func fileForPart(part string) (string, bool) {
62		switch part {
63		case "manifest":
64			return "manifest.json", false
65		case "prompt":
66			return "prompt.md", false
67		case "result":
68			return "result.json", false
69		case "usage":
70			return "usage.json", false
71		case "checks":
72			return "checks.json", false
73		case "embedded":
74			return "embedded", true
75		}
76		return "", false
77	}
78	
79	// IncludeFilter returns a filter callable matching the include list. An empty
80	// list means everything is included.
81	func IncludeFilter(parts []string) func(string) bool {
82		if len(parts) == 0 {
83			parts = allMirrorParts
84		}
85		files := make(map[string]struct{})
86		dirs := make([]string, 0)
87		for _, p := range parts {
88			rel, isDir := fileForPart(strings.ToLower(strings.TrimSpace(p)))
89			if rel == "" {
90				continue
91			}
92			if isDir {
93				dirs = append(dirs, rel+string(filepath.Separator))
94			} else {
95				files[rel] = struct{}{}
96			}
97		}
98		return func(rel string) bool {
99			rel = filepath.ToSlash(rel)
100			// Map back to OS separators for the file lookup.
101			osRel := filepath.FromSlash(rel)
102			if _, ok := files[osRel]; ok {
103				return true
104			}
105			for _, prefix := range dirs {
106				pfx := filepath.ToSlash(prefix)
107				if strings.HasPrefix(rel, pfx) {
108					return true
109				}
110			}
111			return false
112		}
113	}
114	
115	// RenderMirrorPath substitutes the {project}, {attempt_id}, {date}, {bead_id}
116	// placeholders in template. Unknown placeholders are left in place. The
117	// "{date}" expansion uses YYYY-MM-DD derived from the attempt id when it
118	// matches the standard "YYYYMMDDTHHMMSS-..." form, falling back to the
119	// current UTC date.
120	func RenderMirrorPath(template, projectName, attemptID, beadID string) string {
121		date := time.Now().UTC().Format("2006-01-02")
122		if len(attemptID) >= 8 && isAllDigits(attemptID[:8]) {
123			date = fmt.Sprintf("%s-%s-%s", attemptID[0:4], attemptID[4:6], attemptID[6:8])
124		}
125		r := strings.NewReplacer(
126			"{project}", projectName,
127			"{attempt_id}", attemptID,
128			"{date}", date,
129			"{bead_id}", beadID,
130		)
131		return r.Replace(template)
132	}
133	
134	func isAllDigits(s string) bool {
135		for _, c := range s {
136			if c < '0' || c > '9' {
137				return false
138			}
139		}
140		return true
141	}
142	
143	// projectName derives a short identifier from the project root path.
144	func projectName(projectRoot string) string {
145		clean := filepath.Clean(projectRoot)
146		return filepath.Base(clean)
147	}
148	
149	// MirrorBundle uploads one bundle synchronously via the configured backend
150	// and appends a row to the local mirror-index.jsonl pointer file. Returns
151	// the index entry on success.
152	func MirrorBundle(req MirrorRequest) (*MirrorIndexEntry, error) {
153		if req.Cfg == nil || strings.TrimSpace(req.Cfg.Kind) == "" || strings.TrimSpace(req.Cfg.Path) == "" {
154			return nil, fmt.Errorf("mirror not configured")
155		}
156		backend, err := NewMirrorBackend(req.Cfg.Kind)
157		if err != nil {
158			return nil, err
159		}
160		if _, err := os.Stat(req.BundleDir); err != nil {
161			return nil, fmt.Errorf("bundle dir %s: %w", req.BundleDir, err)
162		}
163	
164		dest := RenderMirrorPath(req.Cfg.Path, projectName(req.ProjectRoot), req.AttemptID, req.BeadID)
165		filter := IncludeFilter(req.Cfg.Include)
166	
167		mirrorURI, bytes, err := backend.Upload(dest, req.BundleDir, filter)
168		if err != nil {
169			return nil, fmt.Errorf("mirror upload: %w", err)
170		}
171	
172		entry := &MirrorIndexEntry{
173			AttemptID:  req.AttemptID,
174			BeadID:     req.BeadID,
175			MirrorURI:  mirrorURI,
176			UploadedAt: time.Now().UTC(),
177			ByteSize:   bytes,
178			Kind:       backend.Kind(),
179		}
180		if err := AppendMirrorIndex(req.ProjectRoot, entry); err != nil {
181			return entry, fmt.Errorf("appending mirror-index.jsonl: %w", err)
182		}
183		return entry, nil
184	}
185	
186	// MirrorBundleAsync runs MirrorBundle in a background goroutine and never
187	// returns an error to the caller. Failures are written to mirror.log so the
188	// bead's primary outcome is never affected by mirror-side problems.
189	func MirrorBundleAsync(req MirrorRequest) {
190		go func() {
191			if entry, err := MirrorBundle(req); err != nil {
192				LogMirrorFailure(req.ProjectRoot, req.AttemptID, req.BeadID, err)
193			} else if entry != nil {
194				LogMirrorSuccess(req.ProjectRoot, entry)
195			}
196		}()
197	}
198	
199	// MirrorOrLog dispatches according to the configured async setting. When
200	// the bead description says default async=true, callers should treat a nil
201	// or true Async as background.
202	func MirrorOrLog(req MirrorRequest) {
203		if req.Cfg == nil || strings.TrimSpace(req.Cfg.Kind) == "" || strings.TrimSpace(req.Cfg.Path) == "" {
204			return
205		}
206		async := true
207		if req.Cfg.Async != nil {
208			async = *req.Cfg.Async
209		}
210		if async {
211			MirrorBundleAsync(req)
212			return
213		}
214		if entry, err := MirrorBundle(req); err != nil {
215			LogMirrorFailure(req.ProjectRoot, req.AttemptID, req.BeadID, err)
216		} else if entry != nil {
217			LogMirrorSuccess(req.ProjectRoot, entry)
218		}
219	}
220	
221	// mirrorIndexMu serializes appends to the local pointer file across
222	// goroutines launched by MirrorBundleAsync.
223	var mirrorIndexMu sync.Mutex
224	
225	// AppendMirrorIndex appends one entry to .ddx/executions/mirror-index.jsonl.
226	func AppendMirrorIndex(projectRoot string, entry *MirrorIndexEntry) error {
227		if entry == nil {
228			return nil
229		}
230		mirrorIndexMu.Lock()
231		defer mirrorIndexMu.Unlock()
232	
233		path := filepath.Join(projectRoot, ExecutionsMirrorIndexFile)
234		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
235			return err
236		}
237		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
238		if err != nil {
239			return err
240		}
241		defer f.Close()
242		data, err := json.Marshal(entry)
243		if err != nil {
244			return err
245		}
246		if _, err := f.Write(append(data, '\n')); err != nil {
247			return err
248		}
249		return nil
250	}
251	
252	// ReadMirrorIndex returns every row in mirror-index.jsonl. Missing file is
253	// returned as an empty slice with no error.
254	func ReadMirrorIndex(projectRoot string) ([]MirrorIndexEntry, error) {
255		path := filepath.Join(projectRoot, ExecutionsMirrorIndexFile)
256		data, err := os.ReadFile(path)
257		if err != nil {
258			if os.IsNotExist(err) {
259				return nil, nil
260			}
261			return nil, err
262		}
263		var out []MirrorIndexEntry
264		for _, line := range strings.Split(string(data), "\n") {
265			line = strings.TrimSpace(line)
266			if line == "" {
267				continue
268			}
269			var e MirrorIndexEntry
270			if err := json.Unmarshal([]byte(line), &e); err != nil {
271				continue
272			}
273			out = append(out, e)
274		}
275		return out, nil
276	}
277	
278	// LookupMirrorEntry returns the most recent index entry whose AttemptID
279	// matches the given id, or nil when no such entry exists.
280	func LookupMirrorEntry(projectRoot, attemptID string) (*MirrorIndexEntry, error) {
281		entries, err := ReadMirrorIndex(projectRoot)
282		if err != nil {
283			return nil, err
284		}
285		var match *MirrorIndexEntry
286		for i := range entries {
287			if entries[i].AttemptID == attemptID {
288				match = &entries[i]
289			}
290		}
291		return match, nil
292	}
293	
294	// LogMirrorSuccess records a one-line success entry to mirror.log.
295	func LogMirrorSuccess(projectRoot string, entry *MirrorIndexEntry) {
296		line := fmt.Sprintf("%s OK attempt=%s bead=%s bytes=%d uri=%s\n",
297			time.Now().UTC().Format(time.RFC3339), entry.AttemptID, entry.BeadID, entry.ByteSize, entry.MirrorURI)
298		appendMirrorLog(projectRoot, line)
299	}
300	
301	// LogMirrorFailure records a one-line failure entry to mirror.log.
302	func LogMirrorFailure(projectRoot, attemptID, beadID string, err error) {
303		line := fmt.Sprintf("%s ERR attempt=%s bead=%s err=%q\n",
304			time.Now().UTC().Format(time.RFC3339), attemptID, beadID, err.Error())
305		appendMirrorLog(projectRoot, line)
306	}
307	
308	func appendMirrorLog(projectRoot, line string) {
309		path := filepath.Join(projectRoot, ExecutionsMirrorLogFile)
310		_ = os.MkdirAll(filepath.Dir(path), 0o755)
311		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
312		if err != nil {
313			return
314		}
315		defer f.Close()
316		_, _ = f.WriteString(line)
317	}
318	
319	// NewMirrorBackend returns the backend for a given kind. Currently only
320	// "local" is supported; other kinds return a clear error.
321	func NewMirrorBackend(kind string) (MirrorBackend, error) {
322		switch strings.ToLower(strings.TrimSpace(kind)) {
323		case "local":
324			return &LocalDirMirror{}, nil
325		default:
326			return nil, fmt.Errorf("unsupported mirror kind %q (only 'local' is implemented)", kind)
327		}
328	}
329	
330	// LocalDirMirror copies the bundle into a directory on the local filesystem.
331	// The destination URI is the absolute path that the bundle was written to.
332	type LocalDirMirror struct{}
333	
334	func (LocalDirMirror) Kind() string { return "local" }
335	
336	func (LocalDirMirror) Upload(destURI, srcDir string, includeFilter func(relPath string) bool) (string, int64, error) {
337		if includeFilter == nil {
338			includeFilter = func(string) bool { return true }
339		}
340		if err := os.MkdirAll(destURI, 0o755); err != nil {
341			return "", 0, fmt.Errorf("creating mirror dest %s: %w", destURI, err)
342		}
343		var total int64
344		walkErr := filepath.Walk(srcDir, func(path string, info os.FileInfo, err error) error {
345			if err != nil {
346				return err
347			}
348			if info.IsDir() {
349				return nil
350			}
351			rel, relErr := filepath.Rel(srcDir, path)
352			if relErr != nil {
353				return relErr
354			}
355			if !includeFilter(rel) {
356				return nil
357			}
358			dest := filepath.Join(destURI, rel)
359			if err := os.MkdirAll(filepath.Dir(dest), 0o755); err != nil {
360				return err
361			}
362			n, copyErr := copyFile(path, dest)
363			if copyErr != nil {
364				return copyErr
365			}
366			total += n
367			return nil
368		})
369		if walkErr != nil {
370			return destURI, total, walkErr
371		}
372		return destURI, total, nil
373	}
374	
375	func (LocalDirMirror) Fetch(mirrorURI, destDir string) error {
376		info, err := os.Stat(mirrorURI)
377		if err != nil {
378			return fmt.Errorf("mirror source %s: %w", mirrorURI, err)
379		}
380		if !info.IsDir() {
381			return fmt.Errorf("mirror source %s is not a directory", mirrorURI)
382		}
383		if err := os.MkdirAll(destDir, 0o755); err != nil {
384			return err
385		}
386		return filepath.Walk(mirrorURI, func(path string, info os.FileInfo, err error) error {
387			if err != nil {
388				return err
389			}
390			if info.IsDir() {
391				return nil
392			}
393			rel, relErr := filepath.Rel(mirrorURI, path)
394			if relErr != nil {
395				return relErr
396			}
397			dest := filepath.Join(destDir, rel)
398			if err := os.MkdirAll(filepath.Dir(dest), 0o755); err != nil {
399				return err
400			}
401			_, copyErr := copyFile(path, dest)
402			return copyErr
403		})
404	}
405	
406	func copyFile(src, dst string) (int64, error) {
407		in, err := os.Open(src)
408		if err != nil {
409			return 0, err
410		}
411		defer in.Close()
412		out, err := os.Create(dst)
413		if err != nil {
414			return 0, err
415		}
416		defer out.Close()
417		return io.Copy(out, in)
418	}
