17	// TestRenderMirrorPath verifies the four supported placeholders are
18	// substituted correctly and an unrelated placeholder is left in place.
19	func TestRenderMirrorPath(t *testing.T) {
20		tpl := "/var/lib/ddx-mirror/{project}/{date}/{bead_id}/{attempt_id}"
21		got := RenderMirrorPath(tpl, "axon", "20260418T061717-1993d293", "ddx-5930ed71")
22		want := "/var/lib/ddx-mirror/axon/2026-04-18/ddx-5930ed71/20260418T061717-1993d293"
23		if got != want {
24			t.Fatalf("RenderMirrorPath: got %q want %q", got, want)
25		}
26	
27		// Unrelated placeholders pass through unchanged.
28		got = RenderMirrorPath("/x/{unknown}/{project}", "p", "20260418T010101-aa", "")
29		want = "/x/{unknown}/p"
30		if got != want {
31			t.Fatalf("RenderMirrorPath unknown: got %q want %q", got, want)
32		}
33	}
