35	// TestIncludeFilter verifies that the default filter (empty include list)
36	// matches every part, and that a restricted list excludes embedded.
37	func TestIncludeFilter(t *testing.T) {
38		all := IncludeFilter(nil)
39		for _, name := range []string{"manifest.json", "prompt.md", "result.json", "usage.json", "checks.json", "embedded/agent-1.jsonl"} {
40			if !all(name) {
41				t.Errorf("default filter must accept %q", name)
42			}
43		}
44		noEmbedded := IncludeFilter([]string{"manifest", "result"})
45		cases := []struct {
46			path    string
47			want    bool
48			comment string
49		}{
50			{"manifest.json", true, "manifest in list"},
51			{"result.json", true, "result in list"},
52			{"prompt.md", false, "prompt not in list"},
53			{"embedded/agent-1.jsonl", false, "embedded not in list"},
54		}
55		for _, c := range cases {
56			if got := noEmbedded(c.path); got != c.want {
57				t.Errorf("filter(%q) = %v, want %v (%s)", c.path, got, c.want, c.comment)
58			}
59		}
60	}
