167	// TestMirrorOrLog_FailureDoesNotPanic exercises the failure path: an
168	// unsupported backend kind must be logged but never panic or be returned.
169	func TestMirrorOrLog_FailureDoesNotPanic(t *testing.T) {
170		projectRoot := t.TempDir()
171		bundleDir := filepath.Join(projectRoot, ".ddx", "executions", "x")
172		if err := os.MkdirAll(bundleDir, 0o755); err != nil {
173			t.Fatal(err)
174		}
175		if err := os.WriteFile(filepath.Join(bundleDir, "result.json"), []byte("{}"), 0o644); err != nil {
176			t.Fatal(err)
177		}
178		async := false
179		cfg := &config.ExecutionsMirrorConfig{
180			Kind:  "s3", // unsupported in this implementation
181			Path:  "s3://bucket/{attempt_id}",
182			Async: &async,
183		}
184		MirrorOrLog(MirrorRequest{
185			ProjectRoot: projectRoot,
186			AttemptID:   "x",
187			BeadID:      "ddx-x",
188			BundleDir:   bundleDir,
189			Cfg:         cfg,
190		})
191	
192		logPath := filepath.Join(projectRoot, ExecutionsMirrorLogFile)
193		data, err := os.ReadFile(logPath)
194		if err != nil {
195			t.Fatalf("expected mirror.log to exist after failure: %v", err)
196		}
197		if !strings.Contains(string(data), "ERR") {
198			t.Errorf("mirror.log missing failure marker: %s", data)
199		}
