252	// ReadMirrorIndex returns every row in mirror-index.jsonl. Missing file is
253	// returned as an empty slice with no error.
254	func ReadMirrorIndex(projectRoot string) ([]MirrorIndexEntry, error) {
255		path := filepath.Join(projectRoot, ExecutionsMirrorIndexFile)
256		data, err := os.ReadFile(path)
257		if err != nil {
258			if os.IsNotExist(err) {
259				return nil, nil
260			}
261			return nil, err
262		}
263		var out []MirrorIndexEntry
264		for _, line := range strings.Split(string(data), "\n") {
265			line = strings.TrimSpace(line)
266			if line == "" {
267				continue
268			}
269			var e MirrorIndexEntry
270			if err := json.Unmarshal([]byte(line), &e); err != nil {
271				continue
272			}
273			out = append(out, e)
274		}
275		return out, nil
276	}
