278	// LookupMirrorEntry returns the most recent index entry whose AttemptID
279	// matches the given id, or nil when no such entry exists.
280	func LookupMirrorEntry(projectRoot, attemptID string) (*MirrorIndexEntry, error) {
281		entries, err := ReadMirrorIndex(projectRoot)
282		if err != nil {
283			return nil, err
284		}
285		var match *MirrorIndexEntry
286		for i := range entries {
287			if entries[i].AttemptID == attemptID {
288				match = &entries[i]
289			}
290		}
291		return match, nil
292	}
