319	// NewMirrorBackend returns the backend for a given kind. Currently only
320	// "local" is supported; other kinds return a clear error.
321	func NewMirrorBackend(kind string) (MirrorBackend, error) {
322		switch strings.ToLower(strings.TrimSpace(kind)) {
323		case "local":
324			return &LocalDirMirror{}, nil
325		default:
326			return nil, fmt.Errorf("unsupported mirror kind %q (only 'local' is implemented)", kind)
327		}
328	}
