// copyDirAll recursively copies srcDir to destDir, creating destDir if needed.
func copyDirAll(srcDir, destDir string) error {
	if err := os.MkdirAll(destDir, 0o755); err != nil {
		return err
	}
	return filepath.Walk(srcDir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.IsDir() {
			return nil
		}
		rel, relErr := filepath.Rel(srcDir, path)
		if relErr != nil {
			return relErr
		}
		dst := filepath.Join(destDir, rel)
		if mkErr := os.MkdirAll(filepath.Dir(dst), 0o755); mkErr != nil {
			return mkErr
		}
		_, copyErr := copyFile(path, dst)
		return copyErr
	})
}

// EvidenceMirrorRequest carries everything needed to mirror one attempt's
// local-tier bundle: executions dir, agent-log, and optionally worker dir.
type EvidenceMirrorRequest struct {
	ProjectRoot string
	AttemptID   string
	BeadID      string
	SessionID   string // used to locate agent-<session-id>.jsonl
	WorkerID    string // used to locate .ddx/workers/<worker-id>/
	BundleDir   string // absolute path to .ddx/executions/<attempt-id>/
	Cfg         *config.LocalEvidenceMirrorConfig
}

// MirrorEvidence copies the local-tier evidence bundle to the configured
// mirror destination. Performs no-op when cfg is nil or kind is "none"/empty.
// Returns an error if the executions dir copy fails; agent-log and worker-dir
// copy errors are returned but callers typically log-and-continue.
func MirrorEvidence(req EvidenceMirrorRequest) error {
	cfg := req.Cfg
	if cfg == nil {
		return nil
	}
	kind := strings.ToLower(strings.TrimSpace(cfg.Kind))
	if kind == "" || kind == "none" {
		return nil
	}
	if kind != "local-dir" {
		return fmt.Errorf("unsupported local evidence mirror kind %q (only 'local-dir' is implemented)", kind)
	}
	if strings.TrimSpace(cfg.Path) == "" {
		return fmt.Errorf("local evidence mirror path is empty")
	}

	dest := RenderMirrorPath(cfg.Path, projectName(req.ProjectRoot), req.AttemptID, req.BeadID)

	// Auto-create the mirror root.
	if err := os.MkdirAll(dest, 0o755); err != nil {
		return fmt.Errorf("creating local mirror path %s: %w", dest, err)
	}

	// Copy executions dir.
	execDest := filepath.Join(dest, "executions", req.AttemptID)
	if err := copyDirAll(req.BundleDir, execDest); err != nil {
		return fmt.Errorf("copying executions dir: %w", err)
	}

	// Copy agent log (default: include).
	includeAgentLogs := cfg.IncludeAgentLogs == nil || *cfg.IncludeAgentLogs
	if includeAgentLogs && req.SessionID != "" {
		logName := "agent-" + req.SessionID + ".jsonl"
		src := filepath.Join(req.ProjectRoot, ".ddx", "agent-logs", logName)
		dst := filepath.Join(dest, "agent-logs", logName)
		if mkErr := os.MkdirAll(filepath.Dir(dst), 0o755); mkErr == nil {
			if _, cpErr := copyFile(src, dst); cpErr != nil && !os.IsNotExist(cpErr) {
				return fmt.Errorf("copying agent log: %w", cpErr)
			}
		}
	}

	// Copy worker dir (default: exclude).
	includeWorkers := cfg.IncludeWorkers != nil && *cfg.IncludeWorkers
	if includeWorkers && req.WorkerID != "" {
		srcWorker := filepath.Join(req.ProjectRoot, ".ddx", "workers", req.WorkerID)
		dstWorker := filepath.Join(dest, "workers", req.WorkerID)
		if cpErr := copyDirAll(srcWorker, dstWorker); cpErr != nil && !os.IsNotExist(cpErr) {
			return fmt.Errorf("copying worker dir: %w", cpErr)
		}
	}

	return nil
}

// MirrorEvidenceOrLog calls MirrorEvidence and writes any failure to
// mirror.log with a "mirror-copy-failed" event label. Failures never block
// attempt finalization.
func MirrorEvidenceOrLog(req EvidenceMirrorRequest) {
	cfg := req.Cfg
	if cfg == nil {
		return
	}
	kind := strings.ToLower(strings.TrimSpace(cfg.Kind))
	if kind == "" || kind == "none" {
		return
	}
	if err := MirrorEvidence(req); err != nil {
		logEvidenceMirrorFailure(req.ProjectRoot, req.AttemptID, req.BeadID, err)
	}
}

// logEvidenceMirrorFailure records a "mirror-copy-failed" event to mirror.log.
func logEvidenceMirrorFailure(projectRoot, attemptID, beadID string, err error) {
