	const beadID = "ddx-test-noworker"
	const workerID = "worker-99"

	bundleDir := filepath.Join(projectRoot, ".ddx", "executions", attemptID)
	if err := os.MkdirAll(bundleDir, 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(bundleDir, "result.json"), []byte("{}"), 0o644); err != nil {
		t.Fatal(err)
	}

	workerDir := filepath.Join(projectRoot, ".ddx", "workers", workerID)
	if err := os.MkdirAll(workerDir, 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(workerDir, "status.json"), []byte(`{"pid":0}`), 0o644); err != nil {
		t.Fatal(err)
	}

	mirrorRoot := t.TempDir()
	falseVal := false
	cfg := &config.LocalEvidenceMirrorConfig{
		Kind:           "local-dir",
		Path:           filepath.Join(mirrorRoot, "{attempt_id}"),
		IncludeWorkers: &falseVal, // explicit false
	}

	if err := MirrorEvidence(EvidenceMirrorRequest{
		ProjectRoot: projectRoot,
		AttemptID:   attemptID,
