// TestMirror_CopyFailure_DoesNotBlockFinalization verifies that
// MirrorEvidenceOrLog absorbs errors and logs them without panicking or
// returning an error to the caller.
func TestMirror_CopyFailure_DoesNotBlockFinalization(t *testing.T) {
	projectRoot := t.TempDir()
	const attemptID = "20260510T120004-aabbccdd"
	const beadID = "ddx-test-fail"

	// BundleDir does not exist — copy will fail.
	cfg := &config.LocalEvidenceMirrorConfig{
		Kind: "local-dir",
		Path: filepath.Join(t.TempDir(), "{attempt_id}"),
	}

	// Must not panic.
	MirrorEvidenceOrLog(EvidenceMirrorRequest{
		ProjectRoot: projectRoot,
		AttemptID:   attemptID,
		BeadID:      beadID,
		BundleDir:   filepath.Join(projectRoot, ".ddx", "executions", attemptID), // missing
		Cfg:         cfg,
	})

	logPath := filepath.Join(projectRoot, ExecutionsMirrorLogFile)
	data, err := os.ReadFile(logPath)
	if err != nil {
		t.Fatalf("expected mirror.log after copy failure: %v", err)
	}
	if !strings.Contains(string(data), "mirror-copy-failed") {
		t.Errorf("mirror.log missing 'mirror-copy-failed' marker: %s", data)
	}
}

