// MirrorEvidenceOrLog calls MirrorEvidence and writes any failure to
// mirror.log with a "mirror-copy-failed" event label. Failures never block
// attempt finalization.
func MirrorEvidenceOrLog(req EvidenceMirrorRequest) {
	cfg := req.Cfg
	if cfg == nil {
		return
	}
	kind := strings.ToLower(strings.TrimSpace(cfg.Kind))
	if kind == "" || kind == "none" {
		return
	}
	if err := MirrorEvidence(req); err != nil {
		logEvidenceMirrorFailure(req.ProjectRoot, req.AttemptID, req.BeadID, err)
	}
}

// logEvidenceMirrorFailure records a "mirror-copy-failed" event to mirror.log.
func logEvidenceMirrorFailure(projectRoot, attemptID, beadID string, err error) {
	line := fmt.Sprintf("%s mirror-copy-failed attempt=%s bead=%s err=%q\n",
		time.Now().UTC().Format(time.RFC3339), attemptID, beadID, err.Error())
	appendMirrorLog(projectRoot, line)
}
